solution_code:
#include <iostream>

class Vault {
private:
    int m_balance{ 0 };

public:
    void deposit(int amount)  { m_balance += amount; }

    void withdraw(int amount) {
        if (m_balance >= amount)
            m_balance -= amount;
    }

    int getBalance() const { return m_balance; }
};

int main() {
    int dep, wd;
    std::cin >> dep >> wd;

    Vault v;
    v.deposit(dep);
    v.withdraw(wd);

    std::cout << "Balance: " << v.getBalance() << '\n';
    return 0;
}
